SELECT ipb.description
FROM ip_blocks ipb
JOIN default_views dv ON ipb.default_view = dv.view_id;

SELECT COUNT(*) AS unallocated_count
FROM ip_addresses
WHERE allocated = 0;

SELECT ip_address_id, allocation_date
FROM ip_address_allocations
WHERE allocation_date = (
  SELECT MAX(allocation_date)
  FROM ip_address_allocations
);
